      "systemImage": "network"
    }
  }
}
```

---

## 2. **Plugin Manifest Structure** (`openclaw.plugin.json`)

**Location:** `/extensions/irc/openclaw.plugin.json`

```json
{
  "id": "irc",
  "channels": ["irc"],
  "configSchema": {
    "type": "object",
    "additionalProperties": false,
    "properties": {}
  }
}
