import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  getChatChannelMeta,
} from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";

// ---------------------------------------------------------------------------
// Resolved account stub
// ---------------------------------------------------------------------------

interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
}

const DEFAULT_ACCOUNT_ID = "default";

function resolveAccount(
  _cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  return {
    accountId: accountId ?? DEFAULT_ACCOUNT_ID,
    enabled: true,
    configured: true,
  };
}

// ---------------------------------------------------------------------------
// Plugin definition
// ---------------------------------------------------------------------------

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard (Bulletin)",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Connect to PulseBoard bulletin messaging.",
        order: 100,
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      config: {
        listAccountIds: (_cfg) => [DEFAULT_ACCOUNT_ID],
        resolveAccount,
        defaultAccountId: (_cfg) => DEFAULT_ACCOUNT_ID,
        isConfigured: (account) => account.configured,
      },
      setup: {
        applyAccountConfig: (_params) => ({}) as OpenClawConfig,
      },
      gateway: {
        startAccount: async (ctx) => {
          ctx.log?.info(
            `[${ctx.accountId}] starting PulseBoard provider`,
          );
        },
      },
      messaging: {
        normalizeTarget: (target) => target.trim(),
      },
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ to, text }) => {
        return attachChannelToResult("pulseboard", {
          to,
          messageId: `pb-${Date.now()}`,
        });
      },
    },
  });

